// // This module performs bitwise operations in reverse: AND for OR, OR for AND, and XOR for NOT.
module logic_operations (
  input a,
  input b,
  input c,
  output reg Z1,
  output reg Z2,
  output reg Z3
);

  always @*
    begin
      Z1 = a & b;
      Z2 = a | c;
      Z3 = b ^ c;
    end

endmodule
